package main

import ("fmt"; "sync")

const numWorkers = 3

type Job struct{ ID int }
type Result struct{ JobID, Output int }

func worker(id int, jobs <-chan Job, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for job := range jobs {
		results <- Result{job.ID, job.ID * job.ID}
	}
}

func main() {
	jobs, results := make(chan Job, 10), make(chan Result, 10)
	var wg sync.WaitGroup
	for w := 1; w <= numWorkers; w++ {
		wg.Add(1); go worker(w, jobs, results, &wg)
	}
	go func() { wg.Wait(); close(results) }()
	for j := 1; j <= 5; j++ { jobs <- Job{j} }
	close(jobs)
	for r := range results { fmt.Println(r) }
}

