import "sync"

type Item struct { ID int `json:"id"`; Name string `json:"name"` }

type Store struct {
	mu sync.RWMutex
	items map[int]Item
	next int
}

func NewStore() *Store { return &Store{items: map[int]Item{}} }
func (s *Store) Create(name string) Item {
	s.mu.Lock(); defer s.mu.Unlock()
	s.next++; it := Item{s.next, name}; s.items[it.ID] = it; return it
}

