import "net/http"

func main() {
	store := NewStore()
	http.HandleFunc("/items", func(w http.ResponseWriter, r *http.Request) {
		switch r.Method {
		case http.MethodGet: store.ListHandler(w, r)
		case http.MethodPost: store.CreateHandler(w, r)
		default: http.Error(w, "method", 405)
		}
	})
	http.ListenAndServe(":8080", nil)
}

