type Limiter struct { tokens chan struct{} }

func NewLimiter(cap int, per time.Duration) *Limiter {
	l := &Limiter{tokens: make(chan struct{}, cap)}
	for i := 0; i < cap; i++ { l.tokens <- struct{}{} }
	go func() {
		t := time.NewTicker(per)
		for range t.C { select { case l.tokens <- struct{}{}: default: } }
	}()
	return l
}

